const body = $input.first().json.body;
const transcript = body.transcript || '';
const filename = body.filename || 'manual_onboarding.txt';
const accountId = body.account_id || null;

const fs = require('fs');
const path = `/data/project/dataset/onboarding/${filename}`;
fs.mkdirSync('/data/project/dataset/onboarding', { recursive: true });
fs.writeFileSync(path, transcript);

return [{ json: { path, filename, account_id: accountId } }];

const stdout = $input.first().json.stdout;
const match = stdout.match(/Pipeline B complete: ([\w-]+)/);
const accountId = match ? match[1] : 'unknown';

const fs = require('fs');
const basePath = `/data/project/outputs/accounts/${accountId}/v2`;
let memo = {}, spec = {}, changelog = '', changes = {};
try { memo = JSON.parse(fs.readFileSync(`${basePath}/account_memo.json`, 'utf8')); } catch(e) {}
try { spec = JSON.parse(fs.readFileSync(`${basePath}/agent_spec.json`, 'utf8')); } catch(e) {}
try { changelog = fs.readFileSync(`${basePath}/changelog.md`, 'utf8'); } catch(e) {}
try { changes = JSON.parse(fs.readFileSync(`${basePath}/changes.json`, 'utf8')); } catch(e) {}

return [{ json: { account_id: accountId, memo, spec, changelog, changes_summary: changes.summary || {}, status: 'v2_updated' } }];
